const transcript = $input.item.json.transcript;
const segmentsJson = $input.item.json.response;

// Parse Gemini response
let segments;
try {
  // Remove markdown code blocks if present
  const cleanJson = segmentsJson
    .replace(/```json\n?/g, '')
    .replace(/```\n?/g, '')
    .trim();

  const parsed = JSON.parse(cleanJson);
  segments = parsed.segments;
} catch (error) {
  throw new Error(`Failed to parse segments JSON: ${error.message}`);
}

// Function to extract transcript text for a time range
function extractSegmentText(transcript, startTime, endTime) {
  // Convert MM:SS to seconds
  function timeToSeconds(timeStr) {
    const parts = timeStr.split(':').map(Number);
    if (parts.length === 2) {
      return parts[0] * 60 + parts[1];
    } else if (parts.length === 3) {
      return parts[0] * 3600 + parts[1] * 60 + parts[2];
    }
    return 0;
  }

  const startSec = timeToSeconds(startTime);
  const endSec = timeToSeconds(endTime);

  // Parse transcript and extract relevant portion
  // This is a simplified version - adjust based on your transcript format
  const lines = transcript.split('\n');
  let segmentText = '';

  for (const line of lines) {
    // Try to extract timestamp from line (assuming format like [00:00] or similar)
    const timestampMatch = line.match(/\[(\d{1,2}:\d{2}(?::\d{2})?)\]/);
    if (timestampMatch) {
      const lineSec = timeToSeconds(timestampMatch[1]);
      if (lineSec >= startSec && lineSec <= endSec) {
        segmentText += line.replace(/\[.*?\]/, '').trim() + ' ';
      }
    } else {
      // If no timestamp, include all text (fallback)
      segmentText += line.trim() + ' ';
    }
  }

  // If no timestamped extraction worked, split by proportions
  if (!segmentText.trim()) {
    const totalLength = transcript.length;
    const segmentRatio = (endSec - startSec) / (endSec);
    const startPos = Math.floor((startSec / endSec) * totalLength);
    const endPos = Math.floor((endSec / endSec) * totalLength);
    segmentText = transcript.substring(startPos, endPos);
  }

  return segmentText.trim();
}

// Process each segment
const output = [];
for (const segment of segments) {
  const segmentText = extractSegmentText(
    transcript,
    segment.start_time,
    segment.end_time
  );

  output.push({
    segment_id: segment.segment_id,
    start_time: segment.start_time,
    end_time: segment.end_time,
    topic_hint: segment.topic_hint,
    segment_text: segmentText,
    video_id: $input.item.json.id,
    video_url: $input.item.json.url,
    video_title: $input.item.json.video_title
  });
}

return output.map(item => ({ json: item }));

